import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"HTML Embeds & p5.js","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/html-embeds.md","filePath":"tutorials/html-embeds.md"}'),r={name:"tutorials/html-embeds.md"};function o(l,e,n,d,m,h){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="html-embeds-p5-js" tabindex="-1">HTML Embeds &amp; p5.js <a class="header-anchor" href="#html-embeds-p5-js" aria-label="Permalink to &quot;HTML Embeds &amp; p5.js&quot;">​</a></h1><p>Embed custom interactive content directly on your slides — D3 visualizations, canvas animations, arbitrary HTML, or p5.js sketches.</p><h2 id="html-d3-embed" tabindex="-1">HTML / D3 embed <a class="header-anchor" href="#html-d3-embed" aria-label="Permalink to &quot;HTML / D3 embed&quot;">​</a></h2><ol><li>Click <strong>Embed</strong> in the toolbar.</li><li>A code editor opens with a starter D3 scatter plot.</li><li>Write any valid HTML — the content renders inside a sandboxed iframe.</li><li>Click <strong>Apply</strong> to insert. The element previews live on the slide.</li></ol><p>The embedded HTML is completely self-contained. It works in present mode, exported files, and shared links. External scripts (D3, Three.js, etc.) can be loaded via CDN.</p><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/d3-scatter.html" style="width:100%;height:220px;border:none;"></iframe></div><h2 id="p5-js-sketches" tabindex="-1">p5.js sketches <a class="header-anchor" href="#p5-js-sketches" aria-label="Permalink to &quot;p5.js sketches&quot;">​</a></h2><ol><li>Click <strong>p5</strong> in the toolbar.</li><li>A code editor opens pre-loaded with the p5.js library.</li><li>Write your p5.js sketch using <code>setup()</code> and <code>draw()</code>.</li><li>Click <strong>Apply</strong>. The sketch renders live on the slide.</li></ol><h3 id="example-output-1" tabindex="-1">Example output <a class="header-anchor" href="#example-output-1" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/p5-stars.html" style="width:100%;height:220px;border:none;"></iframe></div><h2 id="manim-animations" tabindex="-1">Manim animations <a class="header-anchor" href="#manim-animations" aria-label="Permalink to &quot;Manim animations&quot;">​</a></h2><ol><li>Click <strong>Manim</strong> in the toolbar.</li><li>Write a Manim scene in the code editor.</li><li>Click <strong>Render</strong> — the server renders the animation and embeds the video.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Manim rendering requires the Manim package installed on the server. Rendering may take several seconds depending on complexity.</p></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>HTML embeds receive <code>EMBED_WIDTH</code> and <code>EMBED_HEIGHT</code> as JavaScript globals — use them to size your canvas responsively.</li><li>Press the <strong>Preview Slide</strong> button in the right panel to test your embed in present mode without navigating through the full deck.</li><li>Embeds support mouse interaction in present mode — hover effects, click handlers, and scroll all work inside the iframe.</li></ul>',16)])])}const u=t(r,[["render",o]]);export{c as __pageData,u as default};
